#include <bits/stdc++.h>
using namespace std;
struct Edge{
	int to,val;
};
int n,m,dist1[1000006],dist2[1000006];
long long ans;
bool f[1000006];
vector<Edge> g1[1000006],g2[1000006];
void SPFA(){
	memset(dist1,127,sizeof(dist1));
	memset(dist2,127,sizeof(dist2));
	queue<int> b;
	b.push(1);
	dist1[1]=0,f[1]=1;
	while(b.size()){
		int u=b.front(),len=g1[u].size();
		b.pop(),f[u]=0;
		for(int i=0;i<len;i++)
			if(dist1[g1[u][i].to]>dist1[u]+g1[u][i].val){
				dist1[g1[u][i].to]=dist1[u]+g1[u][i].val;
				if(!f[g1[u][i].to])
					f[g1[u][i].to]=1,b.push(g1[u][i].to);
			}
	}
	for(int i=1;i<=n;i++)
		ans+=dist1[i];
	b.push(1);
	dist2[1]=0,f[1]=1;
	while(b.size()){
		int u=b.front(),len=g2[u].size();
		b.pop(),f[u]=0;
		for(int i=0;i<len;i++)
			if(dist2[g2[u][i].to]>dist2[u]+g2[u][i].val){
				dist2[g2[u][i].to]=dist2[u]+g2[u][i].val;
				if(!f[g2[u][i].to])
					f[g2[u][i].to]=1,b.push(g2[u][i].to);
			}
	}
	for(int i=1;i<=n;i++)
		ans+=dist2[i];
}
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=m;i++){
		int u,v,w;
		cin>>u>>v>>w;
		g1[u].push_back({v,w});
		g2[v].push_back({u,w});
	}
	SPFA();
	cout<<ans;
	return 0;
}
